    return dt.astimezone(timezone.utc).isoformat().replace("+00:00", "Z")


def _date_only(dt: datetime) -> str:
    return dt.astimezone(timezone.utc).date().isoformat()


def _coerce_datetime(value: Union[str, datetime]) -> datetime:
    if isinstance(value, datetime):
        return value
    # Accept ISO 8601 date or datetime; try datetime first, then date-only
    try:
        # Python 3.11: fromisoformat supports many forms (no Z), handle Z manually
        if value.endswith("Z"):
            return datetime.fromisoformat(value.replace("Z", "+00:00"))
        return datetime.fromisoformat(value)
    except Exception:
        # Treat as date-only (YYYY-MM-DD)
        return datetime.fromisoformat(value + "T00:00:00+00:00")


